import{_ as a,a as e}from"./chunks/查询额度成功.wz9SQqrH.js";import{_ as d,o,c as l,a2 as s}from"./chunks/framework.DnrXFDHb.js";const g=JSON.parse('{"title":"افزودن pCloud Channel","description":"","frontmatter":{},"headers":[],"relativePath":"fa/upload/pcloud.md","filePath":"fa/upload/pcloud.md","lastUpdated":1781962217000}'),n={name:"fa/upload/pcloud.md"};function i(c,t,r,p,h,u){return o(),l("div",null,[...t[0]||(t[0]=[s('<h1 id="افزودن-pcloud-channel" tabindex="-1">افزودن pCloud Channel <a class="header-anchor" href="#افزودن-pcloud-channel" aria-label="Permalink to &quot;افزودن pCloud Channel&quot;">​</a></h1><h2 id="مناسب-برای" tabindex="-1">مناسب برای <a class="header-anchor" href="#مناسب-برای" aria-label="Permalink to &quot;مناسب برای&quot;">​</a></h2><ul><li>pCloud account دارید و می‌خواهید ImgBed images را در pCloud ذخیره کند.</li><li>مشکلی ندارید که pCloud account email و password به‌عنوان channel credentials استفاده شوند.</li></ul><h2 id="ابتدا-چه-چیزهایی-لازم-است" tabindex="-1">ابتدا چه چیزهایی لازم است <a class="header-anchor" href="#ابتدا-چه-چیزهایی-لازم-است" aria-label="Permalink to &quot;ابتدا چه چیزهایی لازم است&quot;">​</a></h2><table tabindex="0"><thead><tr><th>مورد</th><th>چرا لازم است</th></tr></thead><tbody><tr><td>pCloud account email</td><td>برای sign in به pCloud API</td></tr><tr><td>pCloud password</td><td>برای sign in به pCloud API</td></tr><tr><td>API host</td><td>پیش‌فرض <code>api.pcloud.com</code>. برای EU accounts می‌توان از <code>eapi.pcloud.com</code> استفاده کرد.</td></tr><tr><td>Storage directory</td><td>محل ذخیره files. پیش‌فرض <code>imgbed</code>.</td></tr></tbody></table><h2 id="کجا-اضافه-کنیم" tabindex="-1">کجا اضافه کنیم <a class="header-anchor" href="#کجا-اضافه-کنیم" aria-label="Permalink to &quot;کجا اضافه کنیم&quot;">​</a></h2><ol><li>System Settings را باز کنید.</li><li>Upload Settings را باز کنید.</li><li>از گوشه بالا سمت راست <code>Add Channel</code> را بزنید.</li><li><code>pCloud</code> را انتخاب کنید.</li></ol><h2 id="field-reference" tabindex="-1">Field Reference <a class="header-anchor" href="#field-reference" aria-label="Permalink to &quot;Field Reference&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Field</th><th>Purpose</th><th>Required</th></tr></thead><tbody><tr><td>Channel name</td><td>شناسایی این pCloud channel، مثل <code>Personal pCloud</code></td><td>Yes</td></tr><tr><td>Account email</td><td>pCloud login email شما</td><td>Yes</td></tr><tr><td>Password</td><td>pCloud password شما</td><td>Yes</td></tr><tr><td>API host</td><td>pCloud API host. پیش‌فرض <code>api.pcloud.com</code>.</td><td>No</td></tr><tr><td>Storage directory</td><td>directory ذخیره files. پیش‌فرض <code>imgbed</code>.</td><td>No</td></tr></tbody></table><p>بر اساس account region، API host را انتخاب کنید:</p><table tabindex="0"><thead><tr><th>Account Region</th><th>API Host</th></tr></thead><tbody><tr><td>Default / US</td><td><code>api.pcloud.com</code></td></tr><tr><td>Europe</td><td><code>eapi.pcloud.com</code></td></tr></tbody></table><h2 id="مراحل-setup" tabindex="-1">مراحل setup <a class="header-anchor" href="#مراحل-setup" aria-label="Permalink to &quot;مراحل setup&quot;">​</a></h2><ol><li>Upload Settings را باز کنید.</li><li><code>Add Channel</code> را بزنید.</li><li><code>pCloud</code> را انتخاب کنید.</li><li>channel name قابل‌تشخیص وارد کنید.</li><li>pCloud account email را وارد کنید.</li><li>pCloud password را وارد کنید.</li><li>API host را <code>api.pcloud.com</code> نگه دارید، یا برای EU account از <code>eapi.pcloud.com</code> استفاده کنید.</li><li>storage directory را <code>imgbed</code> نگه دارید، یا folder دلخواه وارد کنید.</li><li>channel را save کنید.</li></ol><p><img src="'+a+'" alt="Configure channel" loading="lazy"></p><h2 id="روش-بررسی" tabindex="-1">روش بررسی <a class="header-anchor" href="#روش-بررسی" aria-label="Permalink to &quot;روش بررسی&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Check</th><th>Expected Result</th></tr></thead><tbody><tr><td>Channel card</td><td>پس از Save، pCloud channel card دیده شود.</td></tr><tr><td>Channel switch</td><td>switch روی card enabled بماند.</td></tr><tr><td>Email display</td><td>card، connected pCloud email را نشان دهد.</td></tr><tr><td>Quota query</td><td>پس از query موفق، used و total capacity نمایش داده شود.</td></tr><tr><td>Upload test</td><td>test image در configured pCloud storage directory دیده شود.</td></tr></tbody></table><p><img src="'+e+`" alt="Quota query success" loading="lazy"></p><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><h3 id="چرا-oauth2-نیست؟" tabindex="-1">چرا OAuth2 نیست؟ <a class="header-anchor" href="#چرا-oauth2-نیست؟" aria-label="Permalink to &quot;چرا OAuth2 نیست؟&quot;">​</a></h3><p>pCloud OAuth2 به‌صورت پیش‌فرض self-service نیست. باید به pCloud ایمیل بزنید و بخواهید enable شود.</p><p>flow فعلی pCloud OAuth2 همچنین short-lived upload link workflow موردنیاز ImgBed را پشتیبانی نمی‌کند، بنابراین این channel از account email و password login استفاده می‌کند.</p><h3 id="کدام-api-host-را-استفاده-کنم؟" tabindex="-1">کدام API Host را استفاده کنم؟ <a class="header-anchor" href="#کدام-api-host-را-استفاده-کنم؟" aria-label="Permalink to &quot;کدام API Host را استفاده کنم؟&quot;">​</a></h3><p>Default:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>api.pcloud.com</span></span></code></pre></div><p>برای EU accounts:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>eapi.pcloud.com</span></span></code></pre></div><h2 id="quick-flow" tabindex="-1">Quick Flow <a class="header-anchor" href="#quick-flow" aria-label="Permalink to &quot;Quick Flow&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>pCloud email و password را آماده کنید</span></span>
<span class="line"><span>-&gt; Upload Settings را باز کنید</span></span>
<span class="line"><span>-&gt; Add Channel</span></span>
<span class="line"><span>-&gt; pCloud را انتخاب کنید</span></span>
<span class="line"><span>-&gt; channel name / email / password را وارد کنید</span></span>
<span class="line"><span>-&gt; اگر account شما در Europe نیست، API host را api.pcloud.com نگه دارید</span></span>
<span class="line"><span>-&gt; اگر folder دیگری لازم ندارید، storage directory را imgbed نگه دارید</span></span>
<span class="line"><span>-&gt; Save</span></span>
<span class="line"><span>-&gt; quota query</span></span>
<span class="line"><span>-&gt; test image upload</span></span></code></pre></div>`,28)])])}const C=d(n,[["render",i]]);export{g as __pageData,C as default};
